import{_ as d,o as e,c as o,a2 as a}from"./chunks/framework.Cd7uensT.js";const I=JSON.parse('{"title":"数据模型","description":"","frontmatter":{},"headers":[],"relativePath":"dev/data-model.md","filePath":"dev/data-model.md","lastUpdated":1781664033000}'),r={name:"dev/data-model.md"};function c(n,t,l,i,s,h){return e(),o("div",null,[...t[0]||(t[0]=[a(`<h1 id="数据模型" tabindex="-1">数据模型 <a class="header-anchor" href="#数据模型" aria-label="Permalink to &quot;数据模型&quot;">​</a></h1><h2 id="核心模型关系" tabindex="-1">核心模型关系 <a class="header-anchor" href="#核心模型关系" aria-label="Permalink to &quot;核心模型关系&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Room (机房) ──1:N──► Rack (机柜) ──1:N──► Device (设备)</span></span>
<span class="line"><span>                                              │</span></span>
<span class="line"><span>                    ┌─────────────────────────┼─────────────────────────┐</span></span>
<span class="line"><span>                    ▼                         ▼                         ▼</span></span>
<span class="line"><span>              NetworkCard (网卡)         DevicePort (端口)         DeviceField (字段)</span></span>
<span class="line"><span>                    │                         │</span></span>
<span class="line"><span>                    └─────────────────────────┘</span></span>
<span class="line"><span>                                              │</span></span>
<span class="line"><span>                                              ▼</span></span>
<span class="line"><span>                                          Cable (线缆)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User (用户) ──N:M──► Role (角色)</span></span>
<span class="line"><span>Consumable (耗材) ──N:1──► ConsumableCategory (耗材分类)</span></span>
<span class="line"><span>InventoryPlan (盘点计划) ──1:N──► InventoryTask (盘点任务) ──1:N──► InventoryRecord (盘点记录)</span></span>
<span class="line"><span>                                                                        │</span></span>
<span class="line"><span>                                                                        ▼</span></span>
<span class="line"><span>                                                                  IdleDevice (暂存设备)</span></span></code></pre></div><h2 id="主要模型" tabindex="-1">主要模型 <a class="header-anchor" href="#主要模型" aria-label="Permalink to &quot;主要模型&quot;">​</a></h2><h3 id="机房模型-room" tabindex="-1">机房模型 (Room) <a class="header-anchor" href="#机房模型-room" aria-label="Permalink to &quot;机房模型 (Room)&quot;">​</a></h3><p>机房是系统的顶层物理空间单元，代表一个独立的数据中心机房或设备间。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>roomId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>机房名称，如 &quot;A栋机房&quot;、&quot;B栋3F机房&quot;</td></tr><tr><td><code>location</code></td><td>STRING</td><td>位置描述，如 &quot;A栋3楼&quot;</td></tr><tr><td><code>area</code></td><td>FLOAT</td><td>机房面积（平方米）</td></tr><tr><td><code>manager</code></td><td>STRING</td><td>机房负责人姓名</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>hasMany Rack</code> — 一个机房可包含多个机柜</li></ul><h3 id="机柜模型-rack" tabindex="-1">机柜模型 (Rack) <a class="header-anchor" href="#机柜模型-rack" aria-label="Permalink to &quot;机柜模型 (Rack)&quot;">​</a></h3><p>机柜是机房的组成单元，用于安装设备。以标准 42U 机柜为参考模型。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>rackId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>机柜名称/编号，如 &quot;A-01&quot;、&quot;A-02&quot;</td></tr><tr><td><code>roomId</code></td><td>INTEGER (FK)</td><td>所属机房 ID，关联 Room</td></tr><tr><td><code>totalU</code></td><td>INTEGER</td><td>总 U 位数，标准机柜通常为 42U</td></tr><tr><td><code>usedU</code></td><td>INTEGER</td><td>已占用 U 位数，实时计算更新</td></tr><tr><td><code>powerCapacity</code></td><td>FLOAT</td><td>额定功率容量（W）</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo Room</code> — 属于一个机房</li><li><code>hasMany Device</code> — 可安装多个设备</li></ul><h3 id="设备模型-device" tabindex="-1">设备模型 (Device) <a class="header-anchor" href="#设备模型-device" aria-label="Permalink to &quot;设备模型 (Device)&quot;">​</a></h3><p>设备是系统的核心管理对象，包含服务器、网络设备、存储设备等各类 IT 设备。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>deviceId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>设备名称/别名</td></tr><tr><td><code>type</code></td><td>STRING</td><td>设备类型，如 server、switch、router、storage 等</td></tr><tr><td><code>brand</code></td><td>STRING</td><td>品牌，如 Dell、HP、Cisco 等</td></tr><tr><td><code>model</code></td><td>STRING</td><td>型号</td></tr><tr><td><code>serialNumber</code></td><td>STRING</td><td>序列号（唯一）</td></tr><tr><td><code>rackId</code></td><td>INTEGER (FK)</td><td>所属机柜 ID，关联 Rack</td></tr><tr><td><code>position</code></td><td>INTEGER</td><td>在机柜中的起始 U 位（从底部 1 开始）</td></tr><tr><td><code>height</code></td><td>INTEGER</td><td>占用 U 位数（1U、2U、4U 等）</td></tr><tr><td><code>ipAddress</code></td><td>STRING</td><td>管理 IP 地址</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>设备状态：online、offline、maintenance、retired</td></tr><tr><td><code>customFields</code></td><td>JSON</td><td>自定义字段扩展，存储用户自定义属性</td></tr><tr><td><code>purchaseDate</code></td><td>DATEONLY</td><td>采购日期</td></tr><tr><td><code>warrantyExpiry</code></td><td>DATEONLY</td><td>保修到期日期</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo Rack</code> — 安装在某个机柜中</li><li><code>hasMany DevicePort</code> — 有多个端口</li><li><code>hasMany NetworkCard</code> — 有多块网卡</li><li><code>hasMany Cable</code> — 涉及多条线缆</li></ul><h3 id="端口模型-deviceport" tabindex="-1">端口模型 (DevicePort) <a class="header-anchor" href="#端口模型-deviceport" aria-label="Permalink to &quot;端口模型 (DevicePort)&quot;">​</a></h3><p>端口是设备上的物理网络接口，用于连接线缆实现网络通信。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>portId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>deviceId</code></td><td>INTEGER (FK)</td><td>所属设备 ID，关联 Device</td></tr><tr><td><code>portName</code></td><td>STRING</td><td>端口名称/编号，如 &quot;GigabitEthernet0/1&quot;</td></tr><tr><td><code>portType</code></td><td>STRING</td><td>端口类型，如 RJ45、SFP、SFP+、QSFP 等</td></tr><tr><td><code>speed</code></td><td>STRING</td><td>速率，如 &quot;1Gbps&quot;、&quot;10Gbps&quot;、&quot;25Gbps&quot;</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：active、inactive、disabled</td></tr><tr><td><code>networkCardId</code></td><td>INTEGER (FK)</td><td>绑定的网卡 ID，关联 NetworkCard（可选）</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo Device</code> — 属于某个设备</li><li><code>belongsTo NetworkCard</code> — 可绑定到一块网卡（可选）</li><li><code>hasMany Cable</code> — 可能连接多条线缆</li></ul><h3 id="网卡模型-networkcard" tabindex="-1">网卡模型 (NetworkCard) <a class="header-anchor" href="#网卡模型-networkcard" aria-label="Permalink to &quot;网卡模型 (NetworkCard)&quot;">​</a></h3><p>网卡是设备内部的网络接口卡，一个设备可包含多块网卡。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>cardId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>deviceId</code></td><td>INTEGER (FK)</td><td>所属设备 ID，关联 Device</td></tr><tr><td><code>cardName</code></td><td>STRING</td><td>网卡名称，如 &quot;eth0&quot;、&quot;eth1&quot;</td></tr><tr><td><code>macAddress</code></td><td>STRING</td><td>MAC 地址</td></tr><tr><td><code>model</code></td><td>STRING</td><td>网卡型号</td></tr><tr><td><code>firmwareVersion</code></td><td>STRING</td><td>固件版本</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo Device</code> — 属于某个设备</li><li><code>hasMany DevicePort</code> — 可包含多个端口</li></ul><h3 id="线缆模型-cable" tabindex="-1">线缆模型 (Cable) <a class="header-anchor" href="#线缆模型-cable" aria-label="Permalink to &quot;线缆模型 (Cable)&quot;">​</a></h3><p>线缆连接两个设备（或端口与网卡之间），实现网络拓扑的物理链路。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>cableId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>cableName</code></td><td>STRING</td><td>线缆名称/标签</td></tr><tr><td><code>cableType</code></td><td>STRING</td><td>线缆类型，如 Cat6、Cat6a、OM3、OS2 等</td></tr><tr><td><code>length</code></td><td>FLOAT</td><td>线缆长度（米）</td></tr><tr><td><code>sourceDeviceId</code></td><td>INTEGER (FK)</td><td>源端设备 ID</td></tr><tr><td><code>sourcePortId</code></td><td>INTEGER (FK)</td><td>源端端口 ID</td></tr><tr><td><code>targetDeviceId</code></td><td>INTEGER (FK)</td><td>目标端设备 ID</td></tr><tr><td><code>targetPortId</code></td><td>INTEGER (FK)</td><td>目标端端口 ID</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo Device</code>（sourceDevice / targetDevice）— 涉及两个设备</li><li><code>belongsTo DevicePort</code>（sourcePort / targetPort）— 连接两个端口</li></ul><h3 id="字段模型-devicefield-ticketfield" tabindex="-1">字段模型 (DeviceField / TicketField) <a class="header-anchor" href="#字段模型-devicefield-ticketfield" aria-label="Permalink to &quot;字段模型 (DeviceField / TicketField)&quot;">​</a></h3><p>自定义字段模型允许用户动态扩展设备和工单的属性，无需修改数据库结构。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>fieldId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>module</code></td><td>ENUM</td><td>所属模块：device、ticket</td></tr><tr><td><code>fieldName</code></td><td>STRING</td><td>字段名称（英文标识）</td></tr><tr><td><code>fieldLabel</code></td><td>STRING</td><td>字段显示标签（中文）</td></tr><tr><td><code>fieldType</code></td><td>ENUM</td><td>字段类型：text、number、select、date、boolean</td></tr><tr><td><code>options</code></td><td>JSON</td><td>选项列表（select 类型时使用）</td></tr><tr><td><code>required</code></td><td>BOOLEAN</td><td>是否必填</td></tr><tr><td><code>sortOrder</code></td><td>INTEGER</td><td>排序序号</td></tr></tbody></table><h3 id="工单模型-ticket" tabindex="-1">工单模型 (Ticket) <a class="header-anchor" href="#工单模型-ticket" aria-label="Permalink to &quot;工单模型 (Ticket)&quot;">​</a></h3><p>工单管理故障报修和维护任务的全流程。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>ticketId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>title</code></td><td>STRING</td><td>工单标题</td></tr><tr><td><code>description</code></td><td>TEXT</td><td>详细描述</td></tr><tr><td><code>type</code></td><td>ENUM</td><td>工单类型：fault（故障）、maintenance（维护）</td></tr><tr><td><code>priority</code></td><td>ENUM</td><td>优先级：low、medium、high、critical</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：open、in_progress、resolved、closed</td></tr><tr><td><code>reporterId</code></td><td>INTEGER (FK)</td><td>报告人（用户 ID）</td></tr><tr><td><code>assigneeId</code></td><td>INTEGER (FK)</td><td>处理人（用户 ID）</td></tr><tr><td><code>deviceId</code></td><td>INTEGER (FK)</td><td>关联设备 ID（可选）</td></tr><tr><td><code>customFields</code></td><td>JSON</td><td>自定义字段扩展</td></tr><tr><td><code>createdAt</code></td><td>DATE</td><td>创建时间</td></tr><tr><td><code>resolvedAt</code></td><td>DATE</td><td>解决时间</td></tr></tbody></table><h3 id="耗材模型-consumable" tabindex="-1">耗材模型 (Consumable) <a class="header-anchor" href="#耗材模型-consumable" aria-label="Permalink to &quot;耗材模型 (Consumable)&quot;">​</a></h3><p>耗材管理数据中心使用的各类消耗品，支持 SN 序列号追踪。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>consumableId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>耗材名称</td></tr><tr><td><code>categoryId</code></td><td>INTEGER (FK)</td><td>所属分类 ID</td></tr><tr><td><code>sku</code></td><td>STRING</td><td>库存单位编码</td></tr><tr><td><code>unit</code></td><td>STRING</td><td>计量单位，如 &quot;个&quot;、&quot;箱&quot;、&quot;米&quot;</td></tr><tr><td><code>stock</code></td><td>INTEGER</td><td>当前库存数量</td></tr><tr><td><code>minStock</code></td><td>INTEGER</td><td>最低库存告警阈值</td></tr><tr><td><code>location</code></td><td>STRING</td><td>存放位置</td></tr><tr><td><code>snList</code></td><td>JSON</td><td>SN 序列号列表，用于精确追踪每个耗材</td></tr><tr><td><code>version</code></td><td>INTEGER</td><td>乐观锁版本号，用于并发控制</td></tr></tbody></table><p><strong>关联关系：</strong></p><ul><li><code>belongsTo ConsumableCategory</code> — 属于某个耗材分类</li></ul><h3 id="耗材分类模型-consumablecategory" tabindex="-1">耗材分类模型 (ConsumableCategory) <a class="header-anchor" href="#耗材分类模型-consumablecategory" aria-label="Permalink to &quot;耗材分类模型 (ConsumableCategory)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>categoryId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>分类名称，如 &quot;光纤跳线&quot;、&quot;电源线&quot;、&quot;扎带&quot;</td></tr><tr><td><code>parentId</code></td><td>INTEGER (FK)</td><td>父分类 ID（支持树形分类）</td></tr></tbody></table><h3 id="盘点模型" tabindex="-1">盘点模型 <a class="header-anchor" href="#盘点模型" aria-label="Permalink to &quot;盘点模型&quot;">​</a></h3><p>盘点功能包括计划、任务和记录三层结构。</p><h4 id="盘点计划-inventoryplan" tabindex="-1">盘点计划 (InventoryPlan) <a class="header-anchor" href="#盘点计划-inventoryplan" aria-label="Permalink to &quot;盘点计划 (InventoryPlan)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>planId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>计划名称</td></tr><tr><td><code>scope</code></td><td>JSON</td><td>盘点范围（机房/机柜范围）</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：draft、in_progress、completed</td></tr><tr><td><code>startDate</code></td><td>DATE</td><td>计划开始日期</td></tr><tr><td><code>endDate</code></td><td>DATE</td><td>计划结束日期</td></tr></tbody></table><h4 id="盘点任务-inventorytask" tabindex="-1">盘点任务 (InventoryTask) <a class="header-anchor" href="#盘点任务-inventorytask" aria-label="Permalink to &quot;盘点任务 (InventoryTask)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>taskId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>planId</code></td><td>INTEGER (FK)</td><td>所属盘点计划 ID</td></tr><tr><td><code>assigneeId</code></td><td>INTEGER (FK)</td><td>负责人（用户 ID）</td></tr><tr><td><code>rackId</code></td><td>INTEGER (FK)</td><td>盘点机柜 ID</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：pending、in_progress、completed</td></tr></tbody></table><h4 id="盘点记录-inventoryrecord" tabindex="-1">盘点记录 (InventoryRecord) <a class="header-anchor" href="#盘点记录-inventoryrecord" aria-label="Permalink to &quot;盘点记录 (InventoryRecord)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>recordId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>taskId</code></td><td>INTEGER (FK)</td><td>所属盘点任务 ID</td></tr><tr><td><code>deviceId</code></td><td>INTEGER (FK)</td><td>盘点设备 ID</td></tr><tr><td><code>actualPosition</code></td><td>INTEGER</td><td>实际 U 位位置</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>盘点结果：matched、mismatched、missing、unexpected</td></tr></tbody></table><h4 id="暂存设备-idledevice" tabindex="-1">暂存设备 (IdleDevice) <a class="header-anchor" href="#暂存设备-idledevice" aria-label="Permalink to &quot;暂存设备 (IdleDevice)&quot;">​</a></h4><p>盘点过程中发现的未在册设备或不使用的设备，归入暂存管理。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>idleDeviceId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>设备名称</td></tr><tr><td><code>serialNumber</code></td><td>STRING</td><td>序列号</td></tr><tr><td><code>type</code></td><td>STRING</td><td>设备类型</td></tr><tr><td><code>foundInRack</code></td><td>INTEGER (FK)</td><td>发现时所在机柜 ID</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：pending、in_use、disposed</td></tr><tr><td><code>remark</code></td><td>TEXT</td><td>备注说明</td></tr></tbody></table><h3 id="用户与角色模型" tabindex="-1">用户与角色模型 <a class="header-anchor" href="#用户与角色模型" aria-label="Permalink to &quot;用户与角色模型&quot;">​</a></h3><h4 id="用户模型-user" tabindex="-1">用户模型 (User) <a class="header-anchor" href="#用户模型-user" aria-label="Permalink to &quot;用户模型 (User)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>userId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>username</code></td><td>STRING</td><td>用户名，唯一</td></tr><tr><td><code>password</code></td><td>STRING</td><td>密码（bcrypt 加密存储）</td></tr><tr><td><code>email</code></td><td>STRING</td><td>邮箱</td></tr><tr><td><code>status</code></td><td>ENUM</td><td>状态：active、locked、disabled</td></tr><tr><td><code>loginAttempts</code></td><td>INTEGER</td><td>连续登录失败次数</td></tr><tr><td><code>lockUntil</code></td><td>DATE</td><td>锁定截止时间</td></tr></tbody></table><h4 id="角色模型-role" tabindex="-1">角色模型 (Role) <a class="header-anchor" href="#角色模型-role" aria-label="Permalink to &quot;角色模型 (Role)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>roleId</code></td><td>INTEGER (PK)</td><td>主键，自增</td></tr><tr><td><code>name</code></td><td>STRING</td><td>角色名，如 admin、operator、viewer</td></tr><tr><td><code>description</code></td><td>STRING</td><td>角色描述</td></tr></tbody></table><h2 id="关联关系汇总" tabindex="-1">关联关系汇总 <a class="header-anchor" href="#关联关系汇总" aria-label="Permalink to &quot;关联关系汇总&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关系类型</th><th>源模型</th><th>目标模型</th><th>外键</th></tr></thead><tbody><tr><td>1:N</td><td>Room</td><td>Rack</td><td>Rack.roomId → Room.roomId</td></tr><tr><td>1:N</td><td>Rack</td><td>Device</td><td>Device.rackId → Rack.rackId</td></tr><tr><td>1:N</td><td>Device</td><td>DevicePort</td><td>DevicePort.deviceId → Device.deviceId</td></tr><tr><td>1:N</td><td>Device</td><td>NetworkCard</td><td>NetworkCard.deviceId → Device.deviceId</td></tr><tr><td>1:N</td><td>Device</td><td>Cable（两端）</td><td>Cable.sourceDeviceId / Cable.targetDeviceId → Device.deviceId</td></tr><tr><td>1:N</td><td>DevicePort</td><td>Cable（两端）</td><td>Cable.sourcePortId / Cable.targetPortId → DevicePort.portId</td></tr><tr><td>1:N</td><td>NetworkCard</td><td>DevicePort</td><td>DevicePort.networkCardId → NetworkCard.cardId</td></tr><tr><td>N:M</td><td>User</td><td>Role</td><td>user_roles 中间表</td></tr><tr><td>1:N</td><td>ConsumableCategory</td><td>Consumable</td><td>Consumable.categoryId → ConsumableCategory.categoryId</td></tr><tr><td>1:N</td><td>InventoryPlan</td><td>InventoryTask</td><td>InventoryTask.planId → InventoryPlan.planId</td></tr><tr><td>1:N</td><td>InventoryTask</td><td>InventoryRecord</td><td>InventoryRecord.taskId → InventoryTask.taskId</td></tr></tbody></table><h2 id="数据库建表约定" tabindex="-1">数据库建表约定 <a class="header-anchor" href="#数据库建表约定" aria-label="Permalink to &quot;数据库建表约定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>约定</th></tr></thead><tbody><tr><td>表命名</td><td>snake_case（如 <code>device_ports</code>）</td></tr><tr><td>主键命名</td><td>modelId 格式（如 <code>deviceId</code>）</td></tr><tr><td>外键命名</td><td>关联表名 + Id（如 <code>rackId</code>）</td></tr><tr><td>时间戳</td><td>自动添加 <code>createdAt</code>、<code>updatedAt</code></td></tr><tr><td>字符集（MySQL）</td><td><code>utf8mb4</code> / <code>utf8mb4_unicode_ci</code></td></tr><tr><td>软删除</td><td>使用 <code>paranoid: true</code> 添加 <code>deletedAt</code> 字段</td></tr></tbody></table>`,67)])])}const p=d(r,[["render",c]]);export{I as __pageData,p as default};
